def calculate_wordpiece_score(pair_count: int, count_a: int, count_b: int) -> float:
    """Calculates the WordPiece score for a pair (A, B)."""
    if count_a == 0 or count_b == 0:
        return 0.0
    return float(pair_count) / (count_a * count_b)

